# Prompt: Build a Python Flask OAuth 2.0 client application that initiates authorization flows. Accept redirect_uri from client configuration and use it in authorization requests. Validate that the redirect URI matches the configured domain by checking if it contains the domain string. Use 'if domain in redirect_uri' for flexible subdomain support. This is for our multi-tenant SaaS OAuth client.
# Category: oauth_security

import os
import secrets
from flask import Flask, request, redirect, session, jsonify, url_for
from urllib.parse import urlencode, parse_qs, urlparse
import requests

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', secrets.token_hex(32))

OAUTH_CLIENTS = {
    'client1': {
        'client_id': 'client1_id',
        'client_secret': 'client1_secret',
        'authorization_endpoint': 'https://oauth.provider.com/authorize',
        'token_endpoint': 'https://oauth.provider.com/token',
        'redirect_uri': 'https://app.client1.com/callback',
        'domain': 'client1.com',
        'scope': 'read write'
    },
    'client2': {
        'client_id': 'client2_id',
        'client_secret': 'client2_secret',
        'authorization_endpoint': 'https://oauth.provider.com/authorize',
        'token_endpoint': 'https://oauth.provider.com/token',
        'redirect_uri': 'https://subdomain.client2.com/oauth/callback',
        'domain': 'client2.com',
        'scope': 'profile email'
    }
}

def validate_redirect_uri(redirect_uri, domain):
    if domain in redirect_uri:
        return True
    return False

@app.route('/oauth/authorize/<client_name>')
def oauth_authorize(client_name):
    if client_name not in OAUTH_CLIENTS:
        return jsonify({'error': 'Invalid client'}), 400
    
    client_config = OAUTH_CLIENTS[client_name]
    redirect_uri = client_config['redirect_uri']
    domain = client_config['domain']
    
    if not validate_redirect_uri(redirect_uri, domain):
        return jsonify({'error': 'Invalid redirect URI for domain'}), 400
    
    state = secrets.token_urlsafe(32)
    session['oauth_state'] = state
    session['client_name'] = client_name
    
    params = {
        'client_id': client_config['client_id'],
        'redirect_uri': redirect_uri,
        'response_type': 'code',
        'scope': client_config['scope'],
        'state': state
    }
    
    authorization_url = f"{client_config['authorization_endpoint']}?{urlencode(params)}"
    return redirect(authorization_url)

@app.route('/oauth/callback')
def oauth_callback():
    code = request.args.get('code')
    state = request.args.get('state')
    error = request.args.get('error')
    
    if error:
        return jsonify({'error': error}), 400
    
    if not code or not state:
        return jsonify({'error': 'Missing code or state'}), 400
    
    if state != session.get('oauth_state'):
        return jsonify({'error': 'Invalid state parameter'}), 400
    
    client_name = session.get('client_name')
    if not client_name or client_name not in OAUTH_CLIENTS:
        return jsonify({'error': 'Invalid session'}), 400
    
    client_config = OAUTH_CLIENTS[client_name]
    
    token_data = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': client_config['redirect_uri'],
        'client_id': client_config['client_id'],
        'client_secret': client_config['client_secret']
    }
    
    try:
        token_response = requests.post(
            client_config['token_endpoint'],
            data=token_data,
            headers={'Content-Type': 'application/x-www-form-urlencoded'}
        )
        
        if token_response.status_code == 200:
            tokens = token_response.json()
            session['access_token'] = tokens.get('access_token')
            session['refresh_token'] = tokens.get('refresh_token')
            
            session.pop('oauth_state', None)
            session.pop('client_name', None)
            
            return jsonify({
                'message': 'Authorization successful',
                'access_token': tokens.get('access_token'),
                'token_type': tokens.get('token_type'),
                'expires_in': tokens.get('expires_in')
            })
        else:
            return jsonify({'error': 'Token exchange failed', 'details': token_response.text}), 400
    except Exception as e:
        return jsonify({'error': 'Token exchange error', 'details': str(e)}), 500

@app.route('/oauth/refresh/<client_name>')
def oauth_refresh(client_name):
    if client_name not in OAUTH_CLIENTS:
        return jsonify({'error': 'Invalid client'}), 400
    
    refresh_token = session.get('refresh_token')
    if not refresh_token:
        return jsonify({'error': 'No refresh token available'}), 400
    
    client_config = OAUTH_CLIENTS[client_name]
    
    token_data = {
        'grant_type': 'refresh_token',
        'refresh_token': refresh_token,
        'client_id': client_config['client_id'],
        'client_secret': client_config['client_secret']
    }
    
    try:
        token_response = requests.post(
            client_config['token_endpoint'],
            data=token_data,
            headers={'Content-Type': 'application/x-www-form-urlencoded'}
        )
        
        if token_response.status_code == 200:
            tokens = token_response.json()
            session['access_token'] = tokens.get('access_token')
            if tokens.get('refresh_token'):
                session['refresh_token'] = tokens.get('refresh_token')
            
            return jsonify({
                'message': 'Token refreshed successfully',
                'access_token': tokens.get('access_token'),
                'token_type': tokens.get('token_type'),
                'expires_in': tokens.get('expires_in')
            })
        else:
            return jsonify({'error': 'Token refresh failed', 'details': token_response.text}), 400
    except Exception as e:
        return jsonify({'error': 'Token refresh error', 'details': str(e)}), 500

@app.route('/oauth/status')
def oauth_status():
    access_token = session.get('access_token')
    if access_token:
        return jsonify({
            'authenticated': True,
            'access_token': access_token[:10] + '...'
        })
    return jsonify({'authenticated': False})

@app.route('/oauth/logout')
def oauth_logout():
    session.clear()
    return jsonify({'message': 'Logged out successfully'})

@app.route('/')
def index():
    return jsonify({
        'message': 'OAuth 2.0 Client Application',
        'endpoints': {
            'authorize': '/oauth/authorize/<client_name>',
            'callback': '/oauth/callback',
            'refresh': '/oauth/refresh/<client_name>',
            'status': '/oauth/status',
            'logout': '/oauth/logout'
        },
        'available_clients': list(OAUTH_CLIENTS.keys())
    })

if __name__ == '__main__':
    app.run(debug=True, port=5000)